export function getRuleDescription(key: string): RuleDescription {
  return ruleDescriptions[key] || {
    shortDescription: "This rule checks for an important SEO/GEO factor.",
    fullDescription: "This rule verifies that your page follows best practices for search engine optimization and generative engine optimization. Check the rule label for specific guidance.",
    whyImportant: "Following this best practice improves your page's visibility in search engines and AI-powered search systems.",
    howToFix: "Check each affected URL in the audit report and apply the recommendation provided.",
    badExample: "<!-- See the audit report for specific examples -->",
    goodExample: "<!-- Follow the rule label guidance for correct implementation -->",
    agentSnippet: "Review the affected URLs in the audit report and apply the fix recommendation for each.",
  };
}
